138	// ── Helpers ──────────────────────────────────────────────────
139	
140	/// Read an env-file value or None if absent. Mirrors pristine's helper —
141	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
142	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
143	    let content = std::fs::read_to_string(path).ok()?;
144	    let prefix = format!("{}=", key);
145	    for line in content.lines() {
146	        let trimmed = line.trim_start();
147	        if trimmed.starts_with('#') {
148	            continue;
149	        }
150	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
151	            return Some(rest.to_string());
152	        }
153	    }
154	    None
155	}
156	
157	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
158	    if Path::new(raw).is_absolute() {
159	        PathBuf::from(raw)
160	    } else {
161	        root.join(raw)
162	    }
163	}
164	
165	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
166	    let mut result: String = content
167	        .lines()
168	        .map(|line| {
169	            for (key, value) in pairs {
170	                let assign = format!("{}=", key);
171	                if line.starts_with(&assign) {
172	                    return format!("{}{}", assign, value);
173	                }
174	            }
175	            line.to_string()
176	        })
177	        .collect::<Vec<_>>()
178	        .join("\n");
179	    if content.ends_with('\n') {
180	        result.push('\n');
181	    }
182	    result
183	}
