304	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
305	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
306	    let rbrd = root.join(RBTDGC_RBRD_FILE);
307	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
308	        .ok_or_else(|| format!("RBRD_CLOUD_PREFIX missing from {}", rbrd.display()))?;
309	    Ok(format!("{}d-{}", cloud_prefix, moniker))
310	}
311	
312	/// Cloud-prefix subdir name used in depot fact-file layout
313	/// (`<cloud_prefix>/<moniker>.depot`). Derived from RBRD_CLOUD_PREFIX with
314	/// the structural trailing `-` stripped so it matches the filesystem layout
315	/// emitted by zrbgp_depot_state_emit.
316	fn rbtdrk_cloud_prefix_subdir(root: &Path) -> Result<String, String> {
317	    let rbrd = root.join(RBTDGC_RBRD_FILE);
318	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
319	        .ok_or_else(|| format!("RBRD_CLOUD_PREFIX missing from {}", rbrd.display()))?;
320	    Ok(cloud_prefix.trim_end_matches('-').to_string())
321	}
322	
323	/// Pick the next free moniker for `family_stem` by walking the depot_list
324	/// invocation's BURV output dir for `<family>NNNNNN.depot` files under the
325	/// current cloud_prefix subdir. Returns
326	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
327	/// Restricting the walk to the current cloud_prefix is what makes allocation
328	/// collision-safe: a same-numbered moniker under a foreign cloud_prefix is
329	/// correctly ignored.
330	///
331	/// Caller contract: `list_result` MUST be from a freshly-invoked depot_list
332	/// that ran in the current process. The fact-file scan IS the collision
333	/// check — stale state means picking a colliding moniker. Do not reuse a
334	/// `list_result` across cases or pass an operator-cached value.
335	fn rbtdrk_pick_next_moniker(
336	    list_result: &rbtdri_InvokeResult,
337	    root: &Path,
338	    family_stem: &str,
339	) -> Result<String, String> {
340	    let prefix_dir = rbtdrk_cloud_prefix_subdir(root)?;
341	    let dir = list_result
342	        .burv_output
343	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
344	        .join(&prefix_dir);
345	    let entries = match std::fs::read_dir(&dir) {
346	        Ok(e) => e,
347	        Err(_) => {
348	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
349	        }
350	    };
351	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
352	    let mut max_suffix: Option<u32> = None;
353	    for entry in entries.flatten() {
354	        let name = match entry.file_name().into_string() {
355	            Ok(n) => n,
356	            Err(_) => continue,
357	        };
358	        let stem = match name.strip_suffix(&suffix_ext) {
359	            Some(s) => s,
360	            None => continue,
361	        };
362	        let numeric = match stem.strip_prefix(family_stem) {
363	            Some(s) => s,
364	            None => continue,
365	        };
366	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
367	            continue;
368	        }
369	        let parsed: u32 = match numeric.parse() {
370	            Ok(n) => n,
371	            Err(_) => continue,
372	        };
373	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
374	    }
375	    let next = match max_suffix {
376	        Some(m) => m + 1,
377	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
378	    };
379	    Ok(format!("{}{}", family_stem, next))
380	}
