382	fn rbtdrk_invoke_logged(
383	    ctx: &mut rbtdri_Context,
384	    colophon: &str,
385	    args: &[&str],
386	    extra_env: &[(&str, &str)],
387	    dir: &Path,
388	    label: &str,
389	) -> Result<rbtdri_InvokeResult, String> {
390	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
391	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
392	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
393	    Ok(result)
394	}
