396	// ── Probes ───────────────────────────────────────────────────
397	
398	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
399	/// have no context, so they read the project root from current_dir() — theurge
400	/// always launches from the project root.
401	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
402	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
403	}
404	
405	/// Case 1 probe: rbrr.env exists. Sanity precondition — canonical-establish
406	/// presumes the regime has been initialized at least to the marshal-zero
407	/// blank-template shape.
408	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
409	    let root = rbtdrk_probe_root()?;
410	    let rbrr = root.join(RBTDGC_RBRR_FILE);
411	    if !rbrr.exists() {
412	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
413	    }
414	    Ok(())
415	}
416	
417	/// Case 2 probe: canonical depot moniker installed in rbrd.env. Established
418	/// by case 1; absence means depot-levy didn't run or rbrd.env was rewritten.
419	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
420	    let root = rbtdrk_probe_root()?;
421	    let rbrd = root.join(RBTDGC_RBRD_FILE);
422	    let tincture = rbtdrk_burs_tincture()?;
423	    let family_stem = rbtdrk_family_stem(&tincture);
424	    let moniker =
425	        rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_DEPOT_MONIKER).unwrap_or_default();
426	    if !moniker.starts_with(&family_stem) {
427	        return Err(format!(
428	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
429	            RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker, family_stem
430	        ));
431	    }
432	    Ok(())
433	}
