435	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
436	/// Established by case 2's mantle + canonical-copy step.
437	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
438	    let root = rbtdrk_probe_root()?;
439	    let path = rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_GOVERNOR)?;
440	    if !path.exists() {
441	        return Err(format!("governor RBRA absent at {}", path.display()));
442	    }
443	    Ok(())
444	}
445	
446	// ── Cases ────────────────────────────────────────────────────
447	
448	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
449	/// fresh canest moniker, levies the depot, cross-checks project_id from
450	/// fact-file against the RBDC compose derivation.
451	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
452	    let probe = rbtdrb_Probe {
453	        name: "rbrr.env present",
454	        check: rbtdrk_probe_rbrr_present,
455	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
456	    };
457	    if let Err(v) = rbtdrb_assert(&probe) {
458	        return v;
459	    }
460	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
461	}
462	
463	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
464	    let root = ctx.project_root().to_path_buf();
465	
466	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
467	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
468	    }
469	
470	    let list_pre = match rbtdrk_invoke_logged(
471	        ctx,
472	        RBTDGC_LIST_DEPOT,
473	        &[],
474	        &[],
475	        dir,
476	        "list-pre",
477	    ) {
478	        Ok(r) => r,
479	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
480	    };
481	    if list_pre.exit_code != 0 {
482	        return rbtdre_Verdict::Fail(format!(
483	            "depot list (pre-levy) exit {}\n{}",
484	            list_pre.exit_code, list_pre.stderr
485	        ));
486	    }
487	
488	    let tincture = match rbtdrk_burs_tincture() {
489	        Ok(t) => t,
490	        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
491	    };
492	    let family_stem = rbtdrk_family_stem(&tincture);
493	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, &root, &family_stem) {
494	        Ok(m) => m,
495	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
496	    };
497	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
498	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
499	    }
500	
501	    let levy = match rbtdrk_invoke_logged(
502	        ctx,
503	        RBTDGC_LEVY_DEPOT,
504	        &[],
505	        &[],
506	        dir,
507	        "levy",
508	    ) {
509	        Ok(r) => r,
510	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
511	    };
512	    if levy.exit_code != 0 {
513	        return rbtdre_Verdict::Fail(format!(
514	            "depot levy exit {}\n{}",
515	            levy.exit_code, levy.stderr
516	        ));
517	    }
518	
519	    let list_present = match rbtdrk_invoke_logged(
520	        ctx,
521	        RBTDGC_LIST_DEPOT,
522	        &[],
523	        &[],
524	        dir,
525	        "list-present",
526	    ) {
527	        Ok(r) => r,
528	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
529	    };
530	    if list_present.exit_code != 0 {
531	        return rbtdre_Verdict::Fail(format!(
532	            "depot list (after levy) exit {}\n{}",
533	            list_present.exit_code, list_present.stderr
534	        ));
535	    }
536	
537	    let prefix_dir = match rbtdrk_cloud_prefix_subdir(&root) {
538	        Ok(p) => p,
539	        Err(e) => return rbtdre_Verdict::Fail(format!("resolve cloud_prefix subdir: {}", e)),
540	    };
541	    let fact_path = list_present
542	        .burv_output
543	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
544	        .join(&prefix_dir)
545	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
546	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
547	        Ok(s) => s.trim().to_string(),
548	        Err(e) => {
549	            return rbtdre_Verdict::Fail(format!(
550	                "read depot-project fact '{}': {}",
551	                fact_path.display(),
552	                e
553	            ))
554	        }
555	    };
556	    if fact_project_id.is_empty() {
557	        return rbtdre_Verdict::Fail(format!(
558	            "depot-project fact is empty: {}",
559	            fact_path.display()
560	        ));
561	    }
562	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
563	
564	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
565	        Ok(p) => p,
566	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
567	    };
568	    if composed != fact_project_id {
569	        return rbtdre_Verdict::Fail(format!(
570	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
571	             (RBDC kindle derivation diverged from payor creation)",
572	            composed, fact_project_id
573	        ));
574	    }
575	    rbtdre_Verdict::Pass
576	}
577	
578	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
579	/// reads the SA email fact, copies governor RBRA from BURV output to the
580	/// canonical path under RBRR_SECRETS_DIR.
581	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
582	    let probe = rbtdrb_Probe {
583	        name: "canonical depot moniker installed",
584	        check: rbtdrk_probe_canonical_moniker,
585	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
586	    };
587	    if let Err(v) = rbtdrb_assert(&probe) {
588	        return v;
589	    }
590	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
591	}
592	
593	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
594	    let root = ctx.project_root().to_path_buf();
595	
596	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
597	        Ok(p) => p,
598	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
599	    };
600	
601	    let mantle = match rbtdrk_invoke_logged(
602	        ctx,
603	        RBTDGC_MANTLE_GOVERNOR,
604	        &[],
605	        &[],
606	        dir,
607	        "mantle",
608	    ) {
609	        Ok(r) => r,
610	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
611	    };
612	    if mantle.exit_code != 0 {
613	        return rbtdre_Verdict::Fail(format!(
614	            "governor mantle exit {}\n{}",
615	            mantle.exit_code, mantle.stderr
616	        ));
617	    }
618	
619	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
620	        Ok(s) => s,
621	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
622	    };
623	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
624	
625	    if !assay.exists() {
626	        return rbtdre_Verdict::Fail(format!(
627	            "assay RBRA absent after governor mantle: {}",
628	            assay.display()
629	        ));
630	    }
631	
632	    let canonical = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_GOVERNOR) {
633	        Ok(p) => p,
634	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
635	    };
636	    if let Some(parent) = canonical.parent() {
637	        if let Err(e) = std::fs::create_dir_all(parent) {
638	            return rbtdre_Verdict::Fail(format!(
639	                "create governor RBRA dir {}: {}",
640	                parent.display(),
641	                e
642	            ));
643	        }
644	    }
645	    if let Err(e) = std::fs::copy(&assay, &canonical) {
646	        return rbtdre_Verdict::Fail(format!(
647	            "copy assay RBRA → governor canonical {}: {}",
648	            canonical.display(),
649	            e
650	        ));
651	    }
652	    rbtdre_Verdict::Pass
653	}
654	
655	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
656	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
657	/// propagation before exiting (or the probe iterates internally). No separate
658	/// propagation-wait case.
659	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
660	    let probe = rbtdrb_Probe {
661	        name: "governor RBRA present",
662	        check: rbtdrk_probe_governor_rbra,
663	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
664	    };
665	    if let Err(v) = rbtdrb_assert(&probe) {
666	        return v;
667	    }
668	    rbtdrc_with_ctx(|ctx| {
669	        rbtdrk_role_invest_impl(
670	            ctx,
671	            dir,
672	            RBTDGC_DIVEST_RETRIEVER,
673	            RBTDGC_INVEST_RETRIEVER,
674	            RBTDRK_IDENTITY_RETRIEVER,
675	            RBTDGC_ACCOUNT_RETRIEVER,
676	        )
677	    })
678	}
679	
680	/// Case 4 — director invest + access-probe.
681	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
682	    let probe = rbtdrb_Probe {
683	        name: "governor RBRA present",
684	        check: rbtdrk_probe_governor_rbra,
685	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
686	    };
687	    if let Err(v) = rbtdrb_assert(&probe) {
688	        return v;
689	    }
690	    rbtdrc_with_ctx(|ctx| {
691	        rbtdrk_role_invest_impl(
692	            ctx,
693	            dir,
694	            RBTDGC_DIVEST_DIRECTOR,
695	            RBTDGC_INVEST_DIRECTOR,
696	            RBTDRK_IDENTITY_DIRECTOR,
697	            RBTDGC_ACCOUNT_DIRECTOR,
698	        )
699	    })
700	}
701	
702	/// Shared invest body for retriever and director: invest → assert assay
703	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
704	fn rbtdrk_role_invest_impl(
705	    ctx: &mut rbtdri_Context,
706	    dir: &Path,
707	    divest_colophon: &str,
708	    invest_colophon: &str,
709	    identity: &str,
710	    role: &str,
711	) -> rbtdre_Verdict {
712	    let root = ctx.project_root().to_path_buf();
713	
714	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
715	        Ok(p) => p,
716	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
717	    };
718	
719	    // Invest is fail-loud if the SA already exists (RBSRK/RBSDK preflight), so a
720	    // standing-depot rerun must clear the prior SA first. The divest tabtarget is
721	    // 404-tolerant and confirms the SA is gone before returning, so on a
722	    // freshly-levied depot (canonical-establish) this is a clean no-op and on a
723	    // rerun (canonical-invest) it leaves the invest race-free.
724	    let label_divest = format!("divest-{}", role);
725	    let divest = match rbtdrk_invoke_logged(
726	        ctx,
727	        divest_colophon,
728	        &[identity],
729	        &[],
730	        dir,
731	        &label_divest,
732	    ) {
733	        Ok(r) => r,
734	        Err(e) => return rbtdre_Verdict::Fail(format!("divest {}: {}", role, e)),
735	    };
736	    if divest.exit_code != 0 {
737	        return rbtdre_Verdict::Fail(format!(
738	            "divest {} exit {}\n{}",
739	            role, divest.exit_code, divest.stderr
740	        ));
741	    }
742	
743	    let label_invest = format!("invest-{}", role);
744	    let invest = match rbtdrk_invoke_logged(
745	        ctx,
746	        invest_colophon,
747	        &[identity],
748	        &[],
749	        dir,
750	        &label_invest,
751	    ) {
752	        Ok(r) => r,
753	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
754	    };
755	    if invest.exit_code != 0 {
756	        return rbtdre_Verdict::Fail(format!(
757	            "invest {} exit {}\n{}",
758	            role, invest.exit_code, invest.stderr
759	        ));
760	    }
761	
762	    if !assay.exists() {
763	        return rbtdre_Verdict::Fail(format!(
764	            "assay RBRA absent after invest-{}: {}",
765	            role,
766	            assay.display()
767	        ));
768	    }
769	
770	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
771	        Ok(p) => p,
772	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
773	    };
774	    if let Some(parent) = canonical.parent() {
775	        if let Err(e) = std::fs::create_dir_all(parent) {
776	            return rbtdre_Verdict::Fail(format!(
777	                "create {} RBRA dir {}: {}",
778	                role,
779	                parent.display(),
780	                e
781	            ));
782	        }
783	    }
784	    if let Err(e) = std::fs::copy(&assay, &canonical) {
785	        return rbtdre_Verdict::Fail(format!(
786	            "copy assay RBRA → {} canonical {}: {}",
787	            role,
788	            canonical.display(),
789	            e
790	        ));
791	    }
792	
793	    let probe_colophon = match rbtdrm_credential_check_colophon(role) {
794	        Some(c) => c,
795	        None => return rbtdre_Verdict::Fail(format!("unknown credential role: {}", role)),
796	    };
797	    let probe_result = match rbtdri_invoke_global(ctx, probe_colophon, &[], &[]) {
798	        Ok(r) => r,
799	        Err(e) => {
800	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
801	        }
802	    };
803	    let _ = std::fs::write(
804	        dir.join(format!("probe-{}-stdout.txt", role)),
805	        &probe_result.stdout,
806	    );
807	    let _ = std::fs::write(
808	        dir.join(format!("probe-{}-stderr.txt", role)),
809	        &probe_result.stderr,
810	    );
811	    if probe_result.exit_code != 0 {
812	        return rbtdre_Verdict::Fail(format!(
813	            "access-probe {} exit {}\n{}",
814	            role, probe_result.exit_code, probe_result.stderr
815	        ));
816	    }
817	
818	    rbtdre_Verdict::Pass
819	}
820	
821	// ── Section registry ─────────────────────────────────────────
822	
823	pub static RBTDRK_CASES_CANONICAL_ESTABLISH: &[rbtdre_Case] = &[
824	    case!(rbtdrk_depot_levy),
825	    case!(rbtdrk_governor_mantle),
826	    case!(rbtdrk_retriever_invest),
827	    case!(rbtdrk_director_invest),
828	];
829	
830	pub static RBTDRK_FIXTURE_CANONICAL_ESTABLISH: rbtdre_Fixture = rbtdre_Fixture {
831	    name: RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
832	    disposition: rbtdre_Disposition::StateProgressing,
833	    setup: None,
834	    teardown: None,
835	    cases: RBTDRK_CASES_CANONICAL_ESTABLISH,
836	};
837	
838	// canonical-invest — the skirmish suite's no-levy variant. Reuses the three
839	// investiture case fns verbatim but omits `depot_levy`: skirmish runs against
840	// a depot the operator has levied by hand, so no GCP project is created per
841	// run. Each investiture case carries its own precondition probe (governor
842	// mantle probes the standing depot's moniker; the invests probe the governor),
843	// so the cases compose against an operator-levied depot exactly as they do
844	// after canonical-establish's case 1. Sharing the case fns is the same
845	// provenance-vs-behavior split tadmor/moriah exploit with RBTDRC_CASES_SECURITY.
846	pub static RBTDRK_CASES_CANONICAL_INVEST: &[rbtdre_Case] = &[
847	    case!(rbtdrk_governor_mantle),
848	    case!(rbtdrk_retriever_invest),
849	    case!(rbtdrk_director_invest),
850	];
851	
852	pub static RBTDRK_FIXTURE_CANONICAL_INVEST: rbtdre_Fixture = rbtdre_Fixture {
853	    name: RBTDRM_FIXTURE_CANONICAL_INVEST,
854	    disposition: rbtdre_Disposition::StateProgressing,
855	    setup: None,
856	    teardown: None,
857	    cases: RBTDRK_CASES_CANONICAL_INVEST,
858	};
